#include <comp421/yalnix.h>

#ifndef FILE_SERVER
#define FILE_SERVER 1
#endif

enum {
    MSG_SHUTDOWN = 1
};

struct server_msg {
    int op;
    int padding[7];
};

int main(int argc, char **argv)
{
    struct server_msg msg;
    int pid;

    Register(FILE_SERVER);

    if (argc > 1) {
        pid = Fork();
        if (pid == 0) {
            Exec(argv[1], argv + 1);
            Exit(1);
        }
    }

    for (;;) {
        int sender = Receive(&msg);
        if (sender == 0) {
            break;
        }
        if (sender == ERROR) {
            continue;
        }
        Reply(&msg, sender);
        if (msg.op == MSG_SHUTDOWN) {
            break;
        }
    }

    return 0;
}

#include <stddef.h>
#include <stdint.h>
#include <stdlib.h>
#include <string.h>

#include <comp421/yalnix.h>

#ifndef ERROR
#define ERROR (-1)
#endif

#ifndef SEEK_SET
#define SEEK_SET 0
#endif

#ifndef SEEK_CUR
#define SEEK_CUR 1
#endif

#ifndef SEEK_END
#define SEEK_END 2
#endif

#ifndef INODE_FREE
#define INODE_FREE 0
#endif

#ifndef INODE_REGULAR
#define INODE_REGULAR 2
#endif

#ifndef INODE_DIRECTORY
#define INODE_DIRECTORY 1
#endif

#ifndef INODE_SYMLINK
#define INODE_SYMLINK 3
#endif

#ifndef DIRNAMELEN
#define DIRNAMELEN 30
#endif

#ifndef MAX_OPEN_FILES
#define MAX_OPEN_FILES 16
#endif

#define MAX_INODES 512
#define MAX_SYMLINK_DEPTH 20

#ifndef FILE_SERVER
#define FILE_SERVER 1
#endif

enum {
    MSG_SHUTDOWN = 1
};

struct dir_entry {
    short inum;
    char name[DIRNAMELEN];
};

struct Stat {
    int inum;
    int type;
    int size;
    int nlink;
};

typedef struct Node Node;

typedef struct {
    int used;
    int inum;
    char name[DIRNAMELEN + 1];
} DirSlot;

struct Node {
    int inum;
    int type;
    int nlink;
    int size;
    int reuse;
    unsigned char *data;
    int capacity;
    char *target;
    DirSlot *slots;
    int slot_count;
    int slot_capacity;
};

typedef struct {
    int used;
    int inum;
    int reuse;
    int position;
} OpenFile;

struct server_msg {
    int op;
    int padding[7];
};

static Node g_nodes[MAX_INODES];
static OpenFile g_open_files[MAX_OPEN_FILES];
static int g_initialized;
static int g_cwd_inum;

static void fs_init(void);
static Node *node_by_inum(int inum);
static Node *alloc_node(int type);
static void free_node_contents(Node *node);
static void zero_dirent_name(char dest[DIRNAMELEN], const char *src);
static char *dup_string(const char *src);
static int bounded_strnlen(const char *src, int max_len);
static int name_len_bounded(const char *name);
static int names_equal(const char *a, const char *b);
static int dir_find_slot(Node *dir, const char *name);
static int dir_add_entry(Node *dir, const char *name, int inum);
static int dir_remove_entry(Node *dir, const char *name);
static int dir_is_effectively_empty(Node *dir);
static int split_parent(const char *path, char **parent_out, char name_out[DIRNAMELEN + 1]);
static Node *resolve_path(const char *path, int follow_final, Node *base_dir, int depth);
static int ensure_file_capacity(Node *node, int capacity);
static void truncate_file(Node *node);
static int alloc_fd(Node *node);

static void fs_init(void)
{
    Node *root;

    if (g_initialized) {
        return;
    }

    memset(g_nodes, 0, sizeof(g_nodes));
    memset(g_open_files, 0, sizeof(g_open_files));

    root = &g_nodes[1];
    root->inum = 1;
    root->type = INODE_DIRECTORY;
    root->nlink = 2;
    root->reuse = 1;
    root->slot_capacity = 4;
    root->slots = (DirSlot *) calloc((size_t) root->slot_capacity, sizeof(DirSlot));
    if (root->slots != NULL) {
        root->slot_count = 2;
        root->slots[0].used = 1;
        root->slots[0].inum = 1;
        strcpy(root->slots[0].name, ".");
        root->slots[1].used = 1;
        root->slots[1].inum = 1;
        strcpy(root->slots[1].name, "..");
        root->size = root->slot_count * (int) sizeof(struct dir_entry);
    }

    g_cwd_inum = 1;
    g_initialized = 1;
}

static Node *node_by_inum(int inum)
{
    if (inum <= 0 || inum >= MAX_INODES) {
        return NULL;
    }
    if (g_nodes[inum].inum == 0) {
        return NULL;
    }
    return &g_nodes[inum];
}

static Node *alloc_node(int type)
{
    int i;

    for (i = 1; i < MAX_INODES; i++) {
        if (g_nodes[i].type == INODE_FREE && g_nodes[i].inum != 1) {
            Node *node = &g_nodes[i];
            int next_reuse = node->reuse + 1;
            free_node_contents(node);
            memset(node, 0, sizeof(*node));
            node->inum = i;
            node->type = type;
            node->reuse = next_reuse;
            if (node->reuse <= 0) {
                node->reuse = 1;
            }
            return node;
        }
    }
    for (i = 2; i < MAX_INODES; i++) {
        if (g_nodes[i].inum == 0) {
            Node *node = &g_nodes[i];
            memset(node, 0, sizeof(*node));
            node->inum = i;
            node->type = type;
            node->reuse = 1;
            return node;
        }
    }
    return NULL;
}

static void free_node_contents(Node *node)
{
    if (node == NULL) {
        return;
    }
    free(node->data);
    node->data = NULL;
    node->capacity = 0;
    free(node->target);
    node->target = NULL;
    free(node->slots);
    node->slots = NULL;
    node->slot_count = 0;
    node->slot_capacity = 0;
    node->size = 0;
}

static char *dup_string(const char *src)
{
    char *copy;
    size_t len;

    if (src == NULL) {
        return NULL;
    }
    len = strlen(src);
    copy = (char *) malloc(len + 1);
    if (copy == NULL) {
        return NULL;
    }
    memcpy(copy, src, len + 1);
    return copy;
}

static int bounded_strnlen(const char *src, int max_len)
{
    int len = 0;

    if (src == NULL) {
        return 0;
    }
    while (len < max_len && src[len] != '\0') {
        len++;
    }
    return len;
}

static int name_len_bounded(const char *name)
{
    int len = 0;

    if (name == NULL) {
        return ERROR;
    }
    while (len <= DIRNAMELEN && name[len] != '\0') {
        len++;
    }
    if (len > DIRNAMELEN) {
        return ERROR;
    }
    return len;
}

static int names_equal(const char *a, const char *b)
{
    return strncmp(a, b, DIRNAMELEN + 1) == 0;
}

static int dir_find_slot(Node *dir, const char *name)
{
    int i;

    if (dir == NULL || dir->type != INODE_DIRECTORY || name == NULL) {
        return ERROR;
    }
    for (i = 0; i < dir->slot_count; i++) {
        if (dir->slots[i].used && names_equal(dir->slots[i].name, name)) {
            return i;
        }
    }
    return ERROR;
}

static int dir_add_entry(Node *dir, const char *name, int inum)
{
    int i;
    DirSlot *new_slots;

    if (dir == NULL || dir->type != INODE_DIRECTORY || name_len_bounded(name) == ERROR) {
        return ERROR;
    }
    if (dir_find_slot(dir, name) != ERROR) {
        return ERROR;
    }
    for (i = 0; i < dir->slot_count; i++) {
        if (!dir->slots[i].used) {
            dir->slots[i].used = 1;
            dir->slots[i].inum = inum;
            memset(dir->slots[i].name, 0, sizeof(dir->slots[i].name));
            strcpy(dir->slots[i].name, name);
            dir->size = dir->slot_count * (int) sizeof(struct dir_entry);
            return 0;
        }
    }
    if (dir->slot_count == dir->slot_capacity) {
        int new_capacity = dir->slot_capacity == 0 ? 4 : dir->slot_capacity * 2;
        new_slots = (DirSlot *) realloc(dir->slots, (size_t) new_capacity * sizeof(DirSlot));
        if (new_slots == NULL) {
            return ERROR;
        }
        memset(new_slots + dir->slot_capacity, 0, (size_t) (new_capacity - dir->slot_capacity) * sizeof(DirSlot));
        dir->slots = new_slots;
        dir->slot_capacity = new_capacity;
    }
    dir->slots[dir->slot_count].used = 1;
    dir->slots[dir->slot_count].inum = inum;
    memset(dir->slots[dir->slot_count].name, 0, sizeof(dir->slots[dir->slot_count].name));
    strcpy(dir->slots[dir->slot_count].name, name);
    dir->slot_count += 1;
    dir->size = dir->slot_count * (int) sizeof(struct dir_entry);
    return 0;
}

static int dir_remove_entry(Node *dir, const char *name)
{
    int idx = dir_find_slot(dir, name);

    if (idx == ERROR) {
        return ERROR;
    }
    dir->slots[idx].used = 0;
    dir->slots[idx].inum = 0;
    memset(dir->slots[idx].name, 0, sizeof(dir->slots[idx].name));
    dir->size = dir->slot_count * (int) sizeof(struct dir_entry);
    return 0;
}

static int dir_is_effectively_empty(Node *dir)
{
    int i;

    if (dir == NULL || dir->type != INODE_DIRECTORY) {
        return 0;
    }
    for (i = 0; i < dir->slot_count; i++) {
        if (!dir->slots[i].used) {
            continue;
        }
        if (names_equal(dir->slots[i].name, ".") || names_equal(dir->slots[i].name, "..")) {
            continue;
        }
        return 0;
    }
    return 1;
}

static int split_parent(const char *path, char **parent_out, char name_out[DIRNAMELEN + 1])
{
    const char *end;
    const char *slash;
    size_t parent_len;

    if (path == NULL || parent_out == NULL || name_out == NULL || path[0] == '\0') {
        return ERROR;
    }

    end = path + strlen(path);
    while (end > path && end[-1] == '/') {
        end--;
    }
    if (end == path) {
        return ERROR;
    }

    slash = end;
    while (slash > path && slash[-1] != '/') {
        slash--;
    }

    if ((size_t) (end - slash) > DIRNAMELEN) {
        return ERROR;
    }

    memset(name_out, 0, DIRNAMELEN + 1);
    memcpy(name_out, slash, (size_t) (end - slash));
    if (strchr(name_out, '/') != NULL || name_out[0] == '\0') {
        return ERROR;
    }

    if (slash == path) {
        if (path[0] == '/') {
            *parent_out = dup_string("/");
        } else {
            *parent_out = dup_string(".");
        }
        return *parent_out == NULL ? ERROR : 0;
    }

    parent_len = (size_t) (slash - path);
    while (parent_len > 1 && path[parent_len - 1] == '/') {
        parent_len--;
    }
    *parent_out = (char *) malloc(parent_len + 1);
    if (*parent_out == NULL) {
        return ERROR;
    }
    memcpy(*parent_out, path, parent_len);
    (*parent_out)[parent_len] = '\0';
    return 0;
}

static Node *resolve_path(const char *path, int follow_final, Node *base_dir, int depth)
{
    Node *current;
    const char *p;
    char component[DIRNAMELEN + 1];

    if (depth > MAX_SYMLINK_DEPTH || path == NULL || path[0] == '\0') {
        return NULL;
    }

    fs_init();
    current = (path[0] == '/') ? node_by_inum(1) : (base_dir != NULL ? base_dir : node_by_inum(g_cwd_inum));
    if (current == NULL) {
        return NULL;
    }

    p = path;
    while (*p != '\0') {
        int is_last;
        int idx;
        Node *next;
        const char *start;
        char *combined;
        size_t needed;

        while (*p == '/') {
            p++;
        }
        if (*p == '\0') {
            break;
        }

        start = p;
        while (*p != '\0' && *p != '/') {
            p++;
        }
        if ((size_t) (p - start) > DIRNAMELEN) {
            return NULL;
        }
        memset(component, 0, sizeof(component));
        memcpy(component, start, (size_t) (p - start));

        while (*p == '/') {
            p++;
        }
        is_last = (*p == '\0');

        if (names_equal(component, ".")) {
            continue;
        }
        if (names_equal(component, "..")) {
            idx = dir_find_slot(current, "..");
            if (idx == ERROR) {
                return NULL;
            }
            current = node_by_inum(current->slots[idx].inum);
            if (current == NULL) {
                return NULL;
            }
            continue;
        }
        if (current->type != INODE_DIRECTORY) {
            return NULL;
        }
        idx = dir_find_slot(current, component);
        if (idx == ERROR) {
            return NULL;
        }
        next = node_by_inum(current->slots[idx].inum);
        if (next == NULL) {
            return NULL;
        }
        if (next->type == INODE_SYMLINK && (!is_last || follow_final)) {
            needed = strlen(next->target == NULL ? "" : next->target) + 1 + strlen(p) + 1;
            combined = (char *) malloc(needed);
            if (combined == NULL) {
                return NULL;
            }
            combined[0] = '\0';
            strcat(combined, next->target == NULL ? "" : next->target);
            if (*p != '\0') {
                strcat(combined, "/");
                strcat(combined, p);
            }
            next = resolve_path(combined, 1, current, depth + 1);
            free(combined);
            return next;
        }
        current = next;
    }

    return current;
}

static int ensure_file_capacity(Node *node, int capacity)
{
    unsigned char *new_data;

    if (node == NULL || node->type == INODE_DIRECTORY || capacity < 0) {
        return ERROR;
    }
    if (capacity <= node->capacity) {
        return 0;
    }
    new_data = (unsigned char *) realloc(node->data, (size_t) capacity);
    if (new_data == NULL) {
        return ERROR;
    }
    memset(new_data + node->capacity, 0, (size_t) (capacity - node->capacity));
    node->data = new_data;
    node->capacity = capacity;
    return 0;
}

static void truncate_file(Node *node)
{
    if (node == NULL) {
        return;
    }
    free(node->data);
    node->data = NULL;
    node->capacity = 0;
    node->size = 0;
}

static int alloc_fd(Node *node)
{
    int fd;

    if (node == NULL) {
        return ERROR;
    }
    for (fd = 0; fd < MAX_OPEN_FILES; fd++) {
        if (!g_open_files[fd].used) {
            g_open_files[fd].used = 1;
            g_open_files[fd].inum = node->inum;
            g_open_files[fd].reuse = node->reuse;
            g_open_files[fd].position = 0;
            return fd;
        }
    }
    return ERROR;
}

int Open(char *pathname)
{
    Node *node;

    fs_init();
    node = resolve_path(pathname, 1, NULL, 0);
    if (node == NULL) {
        return ERROR;
    }
    return alloc_fd(node);
}

int Close(int fd)
{
    fs_init();
    if (fd < 0 || fd >= MAX_OPEN_FILES || !g_open_files[fd].used) {
        return ERROR;
    }
    g_open_files[fd].used = 0;
    return 0;
}

int Create(char *pathname)
{
    char *parent_path = NULL;
    char name[DIRNAMELEN + 1];
    Node *existing;
    Node *parent;
    Node *child;
    int fd;

    fs_init();
    if (split_parent(pathname, &parent_path, name) == ERROR) {
        return ERROR;
    }
    existing = resolve_path(pathname, 1, NULL, 0);
    if (existing != NULL) {
        free(parent_path);
        if (existing->type != INODE_REGULAR) {
            return ERROR;
        }
        truncate_file(existing);
        return alloc_fd(existing);
    }
    parent = resolve_path(parent_path, 1, NULL, 0);
    free(parent_path);
    if (parent == NULL || parent->type != INODE_DIRECTORY) {
        return ERROR;
    }
    if (dir_find_slot(parent, name) != ERROR) {
        return ERROR;
    }
    child = alloc_node(INODE_REGULAR);
    if (child == NULL) {
        return ERROR;
    }
    child->nlink = 1;
    if (dir_add_entry(parent, name, child->inum) == ERROR) {
        child->type = INODE_FREE;
        return ERROR;
    }
    fd = alloc_fd(child);
    if (fd == ERROR) {
        dir_remove_entry(parent, name);
        child->type = INODE_FREE;
        return ERROR;
    }
    return fd;
}

int Read(int fd, void *buf, int size)
{
    Node *node;
    int remaining;
    int nread;
    int i;

    fs_init();
    if (fd < 0 || fd >= MAX_OPEN_FILES || !g_open_files[fd].used || size < 0) {
        return ERROR;
    }
    if (size == 0) {
        return 0;
    }
    if (buf == NULL) {
        return ERROR;
    }
    node = node_by_inum(g_open_files[fd].inum);
    if (node == NULL || node->reuse != g_open_files[fd].reuse || node->type == INODE_FREE) {
        return ERROR;
    }
    if (node->type == INODE_DIRECTORY) {
        int total_bytes = node->slot_count * (int) sizeof(struct dir_entry);
        if (g_open_files[fd].position >= total_bytes) {
            return 0;
        }
        nread = size;
        if (nread > total_bytes - g_open_files[fd].position) {
            nread = total_bytes - g_open_files[fd].position;
        }
        for (i = 0; i < nread; i++) {
            int absolute = g_open_files[fd].position + i;
            int slot = absolute / (int) sizeof(struct dir_entry);
            int off = absolute % (int) sizeof(struct dir_entry);
            struct dir_entry temp;

            memset(&temp, 0, sizeof(temp));
            if (slot < node->slot_count && node->slots[slot].used) {
                temp.inum = (short) node->slots[slot].inum;
                zero_dirent_name(temp.name, node->slots[slot].name);
            }
            ((unsigned char *) buf)[i] = ((unsigned char *) &temp)[off];
        }
        g_open_files[fd].position += nread;
        return nread;
    }
    if (g_open_files[fd].position >= node->size) {
        return 0;
    }
    remaining = node->size - g_open_files[fd].position;
    nread = size < remaining ? size : remaining;
    if (nread > 0) {
        memcpy(buf, node->data + g_open_files[fd].position, (size_t) nread);
        g_open_files[fd].position += nread;
    }
    return nread;
}

static void zero_dirent_name(char dest[DIRNAMELEN], const char *src)
{
    memset(dest, 0, DIRNAMELEN);
    if (src == NULL) {
        return;
    }
    memcpy(dest, src, (size_t) bounded_strnlen(src, DIRNAMELEN));
}

int Write(int fd, void *buf, int size)
{
    Node *node;
    int end_position;

    fs_init();
    if (fd < 0 || fd >= MAX_OPEN_FILES || !g_open_files[fd].used || size < 0) {
        return ERROR;
    }
    if (size == 0) {
        return 0;
    }
    if (buf == NULL) {
        return ERROR;
    }
    node = node_by_inum(g_open_files[fd].inum);
    if (node == NULL || node->reuse != g_open_files[fd].reuse || node->type != INODE_REGULAR) {
        return ERROR;
    }
    end_position = g_open_files[fd].position + size;
    if (ensure_file_capacity(node, end_position) == ERROR) {
        return 0;
    }
    memcpy(node->data + g_open_files[fd].position, buf, (size_t) size);
    g_open_files[fd].position = end_position;
    if (end_position > node->size) {
        node->size = end_position;
    }
    return size;
}

int Seek(int fd, int offset, int whence)
{
    Node *node;
    int base;
    int position;

    fs_init();
    if (fd < 0 || fd >= MAX_OPEN_FILES || !g_open_files[fd].used) {
        return ERROR;
    }
    node = node_by_inum(g_open_files[fd].inum);
    if (node == NULL || node->reuse != g_open_files[fd].reuse || node->type == INODE_FREE) {
        return ERROR;
    }
    if (whence == SEEK_SET) {
        base = 0;
    } else if (whence == SEEK_CUR) {
        base = g_open_files[fd].position;
    } else if (whence == SEEK_END) {
        base = (node->type == INODE_DIRECTORY) ? node->slot_count * (int) sizeof(struct dir_entry) : node->size;
    } else {
        return ERROR;
    }
    position = base + offset;
    if (position < 0) {
        return ERROR;
    }
    g_open_files[fd].position = position;
    return position;
}

int Link(char *oldname, char *newname)
{
    Node *oldnode;
    Node *parent;
    char *parent_path = NULL;
    char name[DIRNAMELEN + 1];

    fs_init();
    oldnode = resolve_path(oldname, 0, NULL, 0);
    if (oldnode == NULL || oldnode->type == INODE_DIRECTORY) {
        return ERROR;
    }
    if (split_parent(newname, &parent_path, name) == ERROR) {
        return ERROR;
    }
    parent = resolve_path(parent_path, 1, NULL, 0);
    free(parent_path);
    if (parent == NULL || parent->type != INODE_DIRECTORY || dir_find_slot(parent, name) != ERROR) {
        return ERROR;
    }
    if (dir_add_entry(parent, name, oldnode->inum) == ERROR) {
        return ERROR;
    }
    oldnode->nlink += 1;
    return 0;
}

int Unlink(char *pathname)
{
    char *parent_path = NULL;
    char name[DIRNAMELEN + 1];
    Node *parent;
    Node *node;

    fs_init();
    if (split_parent(pathname, &parent_path, name) == ERROR) {
        return ERROR;
    }
    parent = resolve_path(parent_path, 1, NULL, 0);
    free(parent_path);
    node = resolve_path(pathname, 0, NULL, 0);
    if (parent == NULL || node == NULL || node->type == INODE_DIRECTORY) {
        return ERROR;
    }
    if (dir_remove_entry(parent, name) == ERROR) {
        return ERROR;
    }
    node->nlink -= 1;
    if (node->nlink <= 0) {
        free_node_contents(node);
        node->type = INODE_FREE;
    }
    return 0;
}

int SymLink(char *oldname, char *newname)
{
    char *parent_path = NULL;
    char name[DIRNAMELEN + 1];
    Node *parent;
    Node *node;

    fs_init();
    if (oldname == NULL || oldname[0] == '\0' || split_parent(newname, &parent_path, name) == ERROR) {
        return ERROR;
    }
    parent = resolve_path(parent_path, 1, NULL, 0);
    free(parent_path);
    if (parent == NULL || parent->type != INODE_DIRECTORY || dir_find_slot(parent, name) != ERROR) {
        return ERROR;
    }
    node = alloc_node(INODE_SYMLINK);
    if (node == NULL) {
        return ERROR;
    }
    node->target = dup_string(oldname);
    if (node->target == NULL) {
        node->type = INODE_FREE;
        return ERROR;
    }
    node->size = (int) strlen(node->target);
    node->nlink = 1;
    if (dir_add_entry(parent, name, node->inum) == ERROR) {
        free_node_contents(node);
        node->type = INODE_FREE;
        return ERROR;
    }
    return 0;
}

int ReadLink(char *pathname, char *buf, int len)
{
    Node *node;
    int ncopy;

    fs_init();
    if (buf == NULL || len < 0) {
        return ERROR;
    }
    node = resolve_path(pathname, 0, NULL, 0);
    if (node == NULL || node->type != INODE_SYMLINK || node->target == NULL) {
        return ERROR;
    }
    ncopy = (int) strlen(node->target);
    if (ncopy > len) {
        ncopy = len;
    }
    if (ncopy > 0) {
        memcpy(buf, node->target, (size_t) ncopy);
    }
    return ncopy;
}

int MkDir(char *pathname)
{
    char *parent_path = NULL;
    char name[DIRNAMELEN + 1];
    Node *parent;
    Node *node;

    fs_init();
    if (split_parent(pathname, &parent_path, name) == ERROR) {
        return ERROR;
    }
    parent = resolve_path(parent_path, 1, NULL, 0);
    free(parent_path);
    if (parent == NULL || parent->type != INODE_DIRECTORY || dir_find_slot(parent, name) != ERROR) {
        return ERROR;
    }
    node = alloc_node(INODE_DIRECTORY);
    if (node == NULL) {
        return ERROR;
    }
    node->slot_capacity = 4;
    node->slots = (DirSlot *) calloc((size_t) node->slot_capacity, sizeof(DirSlot));
    if (node->slots == NULL) {
        node->type = INODE_FREE;
        return ERROR;
    }
    node->slot_count = 2;
    node->slots[0].used = 1;
    node->slots[0].inum = node->inum;
    strcpy(node->slots[0].name, ".");
    node->slots[1].used = 1;
    node->slots[1].inum = parent->inum;
    strcpy(node->slots[1].name, "..");
    node->size = node->slot_count * (int) sizeof(struct dir_entry);
    node->nlink = 2;
    if (dir_add_entry(parent, name, node->inum) == ERROR) {
        free_node_contents(node);
        node->type = INODE_FREE;
        return ERROR;
    }
    parent->nlink += 1;
    return 0;
}

int RmDir(char *pathname)
{
    char *parent_path = NULL;
    char name[DIRNAMELEN + 1];
    Node *parent;
    Node *node;

    fs_init();
    if (split_parent(pathname, &parent_path, name) == ERROR) {
        return ERROR;
    }
    if (names_equal(name, ".") || names_equal(name, "..")) {
        free(parent_path);
        return ERROR;
    }
    parent = resolve_path(parent_path, 1, NULL, 0);
    free(parent_path);
    node = resolve_path(pathname, 0, NULL, 0);
    if (parent == NULL || node == NULL || node->type != INODE_DIRECTORY || node->inum == 1) {
        return ERROR;
    }
    if (!dir_is_effectively_empty(node)) {
        return ERROR;
    }
    if (dir_remove_entry(parent, name) == ERROR) {
        return ERROR;
    }
    parent->nlink -= 1;
    free_node_contents(node);
    node->type = INODE_FREE;
    return 0;
}

int ChDir(char *pathname)
{
    Node *node;

    fs_init();
    node = resolve_path(pathname, 1, NULL, 0);
    if (node == NULL || node->type != INODE_DIRECTORY) {
        return ERROR;
    }
    g_cwd_inum = node->inum;
    return 0;
}

int Stat(char *pathname, struct Stat *statbuf)
{
    Node *node;

    fs_init();
    if (statbuf == NULL) {
        return ERROR;
    }
    node = resolve_path(pathname, 0, NULL, 0);
    if (node == NULL) {
        return ERROR;
    }
    statbuf->inum = node->inum;
    statbuf->type = node->type;
    statbuf->size = (node->type == INODE_DIRECTORY) ? node->slot_count * (int) sizeof(struct dir_entry) : node->size;
    statbuf->nlink = node->nlink;
    return 0;
}

int Sync(void)
{
    fs_init();
    return 0;
}

int Shutdown(void)
{
    struct server_msg msg;

    fs_init();
    memset(&msg, 0, sizeof(msg));
    msg.op = MSG_SHUTDOWN;
    Send(&msg, -FILE_SERVER);
    return 0;
}

